(()=>{let t=self;t.addEventListener("push",i=>{let n=i.data?i.data.json():{},o=n.title||"Trinity Prayer House",e={body:n.body||"You have a new notification",icon:"/icon-192x192.png",badge:"/icon-192x192.png",vibrate:[200,100,200],tag:n.tag||"tph-notification",renotify:!0,data:{url:n.url||"/"},actions:n.actions||[]};i.waitUntil(t.registration.showNotification(o,e))}),t.addEventListener("notificationclick",i=>{i.notification.close();let n=i.notification.data?.url||"/";i.waitUntil(t.clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>{for(let n of i)if(n.url.includes(t.location.origin)&&"focus"in n)return n.focus();return t.clients.openWindow(n)}))})})();